import json
import base64
import os
from typing import Tuple, List

MIME_TO_EXTENSION = {
    "image/jpeg": "jpg",
    "image/png": "png",
    "image/webp": "webp",
    "image/gif": "gif",
    "image/bmp": "bmp",
}


def parse_jewelry_data(json_string: str) -> Tuple[str, List[Tuple[bytes, str]]]:
    """
    Парсит JSON-строку с данными о ювелирном изделии.
    Использует нестрогий режим парсинга для обработки управляющих символов.

    :param json_string: Входная строка в формате JSON.
    :return: Кортеж, содержащий:
             1. Строку с характеристиками, разделенными точкой с запятой.
             2. Список кортежей вида (байты_изображения, mime_тип).
    """
    try:
        # Ключевое изменение: strict=False разрешает неэкранированные
        # управляющие символы внутри строковых значений JSON
        data = json.loads(json_string, strict=False)
    except json.JSONDecodeError as e:
        raise ValueError(f"Ошибка десериализации JSON: {e}")

    form_data = data.get("formData", {})
    fields_order = ["type", "purity", "hasStones", "condition", "weight"]
    result_string = ";".join([
        str(form_data.get(field, "")) for field in fields_order
    ])

    images_data = []
    raw_images = data.get("images", [])

    print(f"Обнаружено изображений в JSON: {len(raw_images)}")

    for i, img_uri in enumerate(raw_images):
        try:
            header, encoded_data = img_uri.split(",", 1)
            mime_type = header.split(";")[0].replace("data:", "")

            # Дополнительная очистка base64-строки от возможных пробелов
            # и переносов строк перед декодированием
            encoded_data = "".join(encoded_data.split())

            image_bytes = base64.b64decode(encoded_data)
            images_data.append((image_bytes, mime_type))
            print(f"  Изображение {i + 1}: MIME-тип = {mime_type}, размер = {len(image_bytes)} байт")
        except (ValueError, base64.binascii.Error) as e:
            print(f"  Предупреждение: не удалось обработать изображение {i + 1}: {e}")
            continue

    return result_string, images_data


def save_images(images_data: List[Tuple[bytes, str]], output_dir: str = "output") -> List[str]:
    """
    Сохраняет список изображений в файлы с корректными расширениями.
    """
    os.makedirs(output_dir, exist_ok=True)
    saved_files = []

    for i, (img_bytes, mime_type) in enumerate(images_data):
        ext = MIME_TO_EXTENSION.get(mime_type, "bin")
        filename = os.path.join(output_dir, f"image_{i + 1}.{ext}")

        with open(filename, "wb") as f:
            f.write(img_bytes)
        saved_files.append(filename)
        print(f"Сохранено: {filename}")

    return saved_files


